/**
 * Locus Chamber — redesign Login from the current Figma file.
 *
 * Run this plugin on the page that contains "My profile" and "Login".
 * It keeps the Login frame position, then rebuilds it with Your Chambers
 * colors and Inter typography.
 */

const LOGO_BASE64 = "";

const DEFAULT_W = 390;
const DEFAULT_H = 844;
const PROFILE_NAMES = ["my profile", "profile", "мой профиль"];
const LOGIN_NAMES = ["login", "log in", "sign in", "вход"];

const CHAMBERS_THEME = {
  bg: "#02060d",
  bg2: "#061524",
  surface: "#061524",
  surface2: "#061524",
  text: "#f8e6c8",
  muted: "#bba987",
  line: "#d7a663",
  accent: "#f1bd77",
  accent2: "#e8c48c",
  titleFont: { family: "Inter", style: "Semi Bold" },
  bodyFont: { family: "Inter", style: "Regular" },
  mediumFont: { family: "Inter", style: "Medium" }
};

const FALLBACK_THEME = CHAMBERS_THEME;

function normalizeName(name) {
  return String(name || "").trim().toLowerCase();
}

function hexToRgb(hex) {
  const normalized = hex.replace("#", "");
  const value = parseInt(normalized, 16);
  return {
    r: ((value >> 16) & 255) / 255,
    g: ((value >> 8) & 255) / 255,
    b: (value & 255) / 255
  };
}

function rgbToHex(color) {
  const to255 = (value) => Math.max(0, Math.min(255, Math.round(value * 255)));
  const r = to255(color.r).toString(16).padStart(2, "0");
  const g = to255(color.g).toString(16).padStart(2, "0");
  const b = to255(color.b).toString(16).padStart(2, "0");
  return ("#" + r + g + b).toLowerCase();
}

function solid(hex, opacity) {
  return [{ type: "SOLID", color: hexToRgb(hex), opacity: opacity == null ? 1 : opacity }];
}

function luminance(hex) {
  const color = hexToRgb(hex);
  return 0.2126 * color.r + 0.7152 * color.g + 0.0722 * color.b;
}

function saturation(hex) {
  const color = hexToRgb(hex);
  const max = Math.max(color.r, color.g, color.b);
  const min = Math.min(color.r, color.g, color.b);
  return max === 0 ? 0 : (max - min) / max;
}

function isSolidPaint(paint) {
  return paint && paint.type === "SOLID" && paint.visible !== false && paint.color;
}

function hexFromPaint(paint) {
  return rgbToHex(paint.color);
}

function addPaintColors(map, paints, weight) {
  if (!Array.isArray(paints)) return;
  paints.forEach((paint) => {
    if (!isSolidPaint(paint)) return;
    const hex = hexFromPaint(paint);
    const opacity = paint.opacity == null ? 1 : paint.opacity;
    map.set(hex, (map.get(hex) || 0) + weight * opacity);
  });
}

function findByNames(root, names) {
  const allowed = new Set(names.map(normalizeName));
  const direct = root.children.find((node) => allowed.has(normalizeName(node.name)));
  if (direct) return direct;

  const loose = root.findAll((node) => {
    const normalized = normalizeName(node.name);
    return names.some((name) => normalized.indexOf(name) !== -1);
  });

  return loose.find((node) => node.type === "FRAME") || loose[0] || null;
}

function getChambersTheme() {
  return {
    bg: CHAMBERS_THEME.bg,
    bg2: CHAMBERS_THEME.bg2,
    surface: CHAMBERS_THEME.surface,
    surface2: CHAMBERS_THEME.surface2,
    text: CHAMBERS_THEME.text,
    muted: CHAMBERS_THEME.muted,
    line: CHAMBERS_THEME.line,
    accent: CHAMBERS_THEME.accent,
    accent2: CHAMBERS_THEME.accent2,
    titleFont: CHAMBERS_THEME.titleFont,
    bodyFont: CHAMBERS_THEME.bodyFont,
    mediumFont: CHAMBERS_THEME.mediumFont
  };
}

async function resolveFont(preferred, fallback) {
  const fonts = await figma.listAvailableFontsAsync();
  const match = fonts.find((item) => {
    return item.fontName.family === preferred.family && item.fontName.style === preferred.style;
  });
  if (match) return match.fontName;

  const familyMatch = fonts.find((item) => item.fontName.family === preferred.family);
  if (familyMatch) return familyMatch.fontName;

  const fallbackMatch = fonts.find((item) => {
    return item.fontName.family === fallback.family && item.fontName.style === fallback.style;
  });
  return fallbackMatch ? fallbackMatch.fontName : fonts[0].fontName;
}

function base64ToBytes(base64) {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

function clearFrame(frame) {
  while (frame.children.length > 0) {
    frame.children[0].remove();
  }
}

function makeFrame(parent, name, x, y, w, h, fills) {
  const frame = figma.createFrame();
  frame.name = name;
  frame.resize(w, h);
  frame.x = x;
  frame.y = y;
  frame.fills = fills || [];
  parent.appendChild(frame);
  return frame;
}

function makeRect(parent, name, x, y, w, h, fills, radius) {
  const rect = figma.createRectangle();
  rect.name = name;
  rect.resize(w, h);
  rect.x = x;
  rect.y = y;
  rect.fills = fills || [];
  rect.cornerRadius = radius || 0;
  parent.appendChild(rect);
  return rect;
}

function makeText(parent, name, text, x, y, w, font, size, color, lineHeight, opacity) {
  const node = figma.createText();
  node.name = name;
  node.fontName = font;
  node.characters = text;
  node.fontSize = size;
  node.lineHeight = { unit: "PIXELS", value: lineHeight || Math.round(size * 1.35) };
  node.fills = solid(color, opacity == null ? 1 : opacity);
  node.textAutoResize = "HEIGHT";
  node.resize(w, node.height);
  node.x = x;
  node.y = y;
  parent.appendChild(node);
  return node;
}

function addGlow(parent, theme, w, h) {
  const topGlow = makeRect(parent, "Ambient glow — top", -82, -54, w + 164, 220, solid(theme.accent, 0.05), 160);
  topGlow.effects = [{ type: "LAYER_BLUR", radius: 48, visible: true }];

  const bottomGlow = makeRect(
    parent,
    "Ambient glow — bottom",
    w - 168,
    h - 200,
    220,
    220,
    solid(theme.line, 0.04),
    160
  );
  bottomGlow.effects = [{ type: "LAYER_BLUR", radius: 40, visible: true }];
}

function addLogo(parent, theme, imageHash, cx, y) {
  const wrap = makeFrame(parent, "Logo lockup", cx - 72, y, 144, 144, solid(theme.bg2, 0.88));
  wrap.cornerRadius = 34;
  wrap.clipsContent = true;
  wrap.strokes = solid(theme.line, 0.32);
  wrap.strokeWeight = 1;
  wrap.effects = [
    {
      type: "DROP_SHADOW",
      color: { r: 0, g: 0, b: 0, a: 0.35 },
      offset: { x: 0, y: 10 },
      radius: 24,
      visible: true,
      blendMode: "NORMAL"
    }
  ];

  const image = makeRect(wrap, "Locus Chamber logo", 0, 0, 144, 144, [], 34);
  image.fills = [{ type: "IMAGE", imageHash, scaleMode: "FILL" }];
  return wrap;
}

function addStatusBar(parent, theme, w) {
  makeText(parent, "Status time", "9:41", 24, 16, 60, theme.mediumFont, 14, theme.text, 18, 0.95);
  const icons = makeFrame(parent, "Status icons", w - 76, 20, 52, 10, []);
  [0, 17, 34].forEach((x, index) => {
    makeRect(icons, "Status dot " + (index + 1), x, 1, index === 2 ? 18 : 12, 7, solid(theme.text, index === 2 ? 0.82 : 0.42), 3);
  });
}

function addInput(parent, theme, y, label, value, secure) {
  const cardInset = 24;
  const fieldInset = 16;
  const fieldW = parent.width - cardInset * 2;

  makeText(parent, label + " label", label, cardInset, y, fieldW, theme.mediumFont, 12, theme.muted, 16, 0.92);

  const field = figma.createFrame();
  field.name = label + " field";
  field.resize(fieldW, 52);
  field.x = cardInset;
  field.y = y + 22;
  field.layoutMode = "HORIZONTAL";
  field.primaryAxisAlignItems = "CENTER";
  field.counterAxisAlignItems = "CENTER";
  field.paddingLeft = fieldInset;
  field.paddingRight = fieldInset;
  field.paddingTop = 14;
  field.paddingBottom = 14;
  field.itemSpacing = 8;
  field.cornerRadius = 16;
  field.fills = solid(theme.bg, 0.92);
  field.strokes = solid(theme.line, 0.28);
  field.strokeWeight = 1;
  parent.appendChild(field);

  const valueText = figma.createText();
  valueText.name = label + " value";
  valueText.fontName = theme.bodyFont;
  valueText.characters = secure ? "••••••••" : value;
  valueText.fontSize = secure ? 18 : 14;
  valueText.lineHeight = { unit: "PIXELS", value: 20 };
  valueText.fills = solid(theme.text, secure ? 0.88 : 0.76);
  valueText.textAutoResize = "HEIGHT";
  valueText.resize(fieldW - fieldInset * 2 - (secure ? 48 : 0), valueText.height);
  field.appendChild(valueText);
  valueText.layoutGrow = 1;
  valueText.layoutSizingHorizontal = "FILL";

  if (secure) {
    const reveal = figma.createText();
    reveal.name = "Password reveal";
    reveal.fontName = theme.mediumFont;
    reveal.characters = "Show";
    reveal.fontSize = 12;
    reveal.lineHeight = { unit: "PIXELS", value: 16 };
    reveal.fills = solid(theme.accent, 0.95);
    reveal.textAutoResize = "WIDTH_AND_HEIGHT";
    field.appendChild(reveal);
  }

  return field;
}

function addLoginContent(login, theme, imageHash) {
  const w = login.width;
  const h = login.height;

  addGlow(login, theme, w, h);
  makeRect(login, "Background overlay", 0, 0, w, h, solid(theme.bg2, 0.42), 0);
  addStatusBar(login, theme, w);
  addLogo(login, theme, imageHash, w / 2, 86);

  makeText(login, "Login title", "Welcome back", 36, 252, w - 72, theme.titleFont, 30, theme.text, 36, 1);
  makeText(
    login,
    "Login subtitle",
    "Step into your chamber and continue building a living map of memories.",
    36,
    294,
    w - 72,
    theme.bodyFont,
    14,
    theme.muted,
    21,
    0.9
  );

  const card = makeFrame(login, "Login form card", 24, 374, w - 48, 322, solid(theme.surface, 0.62));
  card.cornerRadius = 18;
  card.strokes = solid(theme.line, 0.28);
  card.strokeWeight = 1;
  card.effects = [
    {
      type: "DROP_SHADOW",
      color: { r: 0, g: 0, b: 0, a: 0.28 },
      offset: { x: 0, y: 12 },
      radius: 24,
      visible: true,
      blendMode: "NORMAL"
    }
  ];

  makeText(card, "Form eyebrow", "LOCUS CHAMBER", 24, 24, 220, theme.mediumFont, 11, theme.accent, 16, 0.96);
  addInput(card, theme, 58, "Email", "alice@example.com", false);
  addInput(card, theme, 146, "Password", "", true);

  const buttonW = card.width - 48;
  const button = makeFrame(card, "Primary button", 24, 244, buttonW, 54, solid(theme.accent, 1));
  button.cornerRadius = 18;
  button.effects = [
    {
      type: "DROP_SHADOW",
      color: { r: 0, g: 0, b: 0, a: 0.24 },
      offset: { x: 0, y: 8 },
      radius: 16,
      visible: true,
      blendMode: "NORMAL"
    }
  ];
  makeText(button, "Primary button label", "Log in", 0, 17, buttonW, theme.mediumFont, 15, theme.bg2, 20, 1);
  button.children[0].textAlignHorizontal = "CENTER";

  makeText(login, "Forgot password", "Forgot password?", 36, 718, w - 72, theme.mediumFont, 13, theme.accent, 18, 0.92).textAlignHorizontal = "CENTER";
  makeText(login, "Create account", "New here? Create your chamber", 36, 754, w - 72, theme.bodyFont, 13, theme.muted, 18, 0.84).textAlignHorizontal = "CENTER";

  const indicator = makeRect(login, "Home indicator", (w - 120) / 2, h - 16, 120, 4, solid(theme.text, 0.28), 2);
  indicator.name = "Home indicator";
}

function ensureLoginFrame(page, profile, loginCandidate) {
  if (loginCandidate && loginCandidate.type === "FRAME") return loginCandidate;

  const frame = figma.createFrame();
  frame.name = "Login";
  frame.resize(DEFAULT_W, DEFAULT_H);
  frame.x = profile ? profile.x + profile.width + 48 : 0;
  frame.y = profile ? profile.y : 0;
  page.appendChild(frame);
  return frame;
}

async function redesignLogin() {
  const page = figma.currentPage;
  const profile = findByNames(page, PROFILE_NAMES);
  const loginCandidate = findByNames(page, LOGIN_NAMES);
  const login = ensureLoginFrame(page, profile, loginCandidate);
  const theme = getChambersTheme();

  theme.titleFont = await resolveFont(theme.titleFont, CHAMBERS_THEME.titleFont);
  theme.bodyFont = await resolveFont(theme.bodyFont, CHAMBERS_THEME.bodyFont);
  theme.mediumFont = await resolveFont(theme.mediumFont, CHAMBERS_THEME.mediumFont);

  await figma.loadFontAsync(theme.titleFont);
  await figma.loadFontAsync(theme.bodyFont);
  await figma.loadFontAsync(theme.mediumFont);

  const logoBytes = base64ToBytes(LOGO_BASE64);
  const logoImage = figma.createImage(logoBytes);

  if (login.width < 300 || login.height < 600) {
    login.resize(DEFAULT_W, DEFAULT_H);
  }

  clearFrame(login);
  login.name = "Login";
  login.clipsContent = true;
  login.cornerRadius = login.cornerRadius || 40;
  login.fills = solid(theme.bg, 1);
  login.strokes = solid(theme.line, 0.24);
  login.strokeWeight = 1;

  addLoginContent(login, theme, logoImage.hash);

  figma.viewport.scrollAndZoomIntoView([login]);
  figma.closePlugin('Login redesigned with Your Chambers colors and Inter typography.');
}

redesignLogin().catch((err) => {
  figma.closePlugin("Error: " + err.message);
});
